def compute_rate(events, duration):
    if duration == 0:
        return 0  # Prevent ZeroDivisionError by returning 0 when duration is zero
    return events / duration

def run():
    result = compute_rate(100, 0)
    return result

if __name__ == "__main__":
    try:
        run()
